import React, { useState } from "react";

const serviceData = {

  "Water Services": [
    { name: "KDMC Water Tanker Booking", phone: "0251-2480400", desc: "Book emergency water tanker through KDMC Water Department" },
    { name: "Water Supply Complaint", phone: "18002663535", desc: "Report water leakage or low pressure issue" }
  ],

  "Waste Management": [
    { name: "Garbage Pickup Request", phone: "0251-2480600", desc: "Schedule garbage or bulk waste pickup" },
    { name: "Dead Animal Removal", phone: "0251-2480600", desc: "Emergency animal removal service" }
  ],

  "Electrical Services": [
    { name: "Electricity Complaint (MSEDCL)", phone: "1912", desc: "Power failure & meter complaint" },
    { name: "Street Light Repair", phone: "0251-2480700", desc: "Report faulty street lights" }
  ],

  "Civil Maintenance": [
    { name: "Drainage Complaint", phone: "0251-2480650", desc: "Blocked drainage or sewage overflow" },
    { name: "Road Repair Complaint", phone: "0251-2480550", desc: "Potholes and road damage complaint" }
  ],

  "Health & Sanitation": [
    { name: "Mosquito Fogging Request", phone: "0251-2480450", desc: "Fogging for dengue & malaria prevention" },
    { name: "Public Toilet Complaint", phone: "0251-2480620", desc: "Report sanitation issues" }
  ]

};

function Services() {

  const tabs = Object.keys(serviceData);
  const [activeTab, setActiveTab] = useState(tabs[0]);
  const [search, setSearch] = useState("");

  const filteredServices = serviceData[activeTab].filter(item =>
    item.name.toLowerCase().includes(search.toLowerCase())
  );

  return (
    <div style={styles.container}>

      {/* Header */}
      <div style={styles.header}>
        <h1>🏙 KDMC Citizen Services Portal</h1>
        <p>Book civic services & lodge complaints instantly</p>
      </div>

      {/* Search */}
      <input
        style={styles.searchBox}
        placeholder="Search service..."
        value={search}
        onChange={(e) => setSearch(e.target.value)}
      />

      {/* Tabs */}
      <div style={styles.tabs}>
        {tabs.map(tab => (
          <button
            key={tab}
            onClick={() => { setActiveTab(tab); setSearch(""); }}
            style={{
              ...styles.tabBtn,
              background: activeTab === tab ? "#00cec9" : "transparent"
            }}
          >
            {tab}
          </button>
        ))}
      </div>

      {/* Cards */}
      <div style={styles.grid}>

        {filteredServices.map((item, index) => (
          <div key={index} style={styles.card}>

            <h3>{item.name}</h3>
            <p style={{ opacity: 0.9 }}>{item.desc}</p>
            <p>📞 {item.phone}</p>

            <div style={styles.btnRow}>

              <a href={`tel:${item.phone}`} style={styles.callBtn}>
                Call Now
              </a>

              <button style={styles.reqBtn}>
                Request Service
              </button>

            </div>

          </div>
        ))}

      </div>

    </div>
  );
}

const styles = {

  container: {
    minHeight: "100vh",
    padding: "20px",
    background: "linear-gradient(135deg,#16222A,#3A6073)",
    color: "#fff",
    fontFamily: "Segoe UI"
  },

  header: {
    textAlign: "center",
    marginBottom: "15px"
  },

  searchBox: {
    width: "100%",
    padding: "12px",
    borderRadius: "10px",
    border: "none",
    marginBottom: "15px"
  },

  tabs: {
    display: "flex",
    flexWrap: "wrap",
    justifyContent: "center",
    gap: "10px",
    marginBottom: "20px"
  },

  tabBtn: {
    padding: "10px 18px",
    borderRadius: "20px",
    border: "1px solid #00cec9",
    color: "#fff",
    cursor: "pointer"
  },

  grid: {
    display: "grid",
    gridTemplateColumns: "repeat(auto-fit,minmax(260px,1fr))",
    gap: "20px"
  },

  card: {
    background: "rgba(255,255,255,0.1)",
    padding: "20px",
    borderRadius: "15px",
    boxShadow: "0 10px 20px rgba(0,0,0,0.5)"
  },

  btnRow: {
    display: "flex",
    justifyContent: "space-between",
    marginTop: "12px"
  },

  callBtn: {
    background: "#00cec9",
    padding: "8px 15px",
    borderRadius: "20px",
    textDecoration: "none",
    color: "#000",
    fontWeight: "bold"
  },

  reqBtn: {
    background: "#0984e3",
    padding: "8px 15px",
    borderRadius: "20px",
    border: "none",
    color: "#fff",
    cursor: "pointer"
  }

};

export default Services;
